     1→/**
     2→ * Diagram Canvas Component
     3→ * Konva Stage wrapper with grid, pan, zoom
     4→ */
     5→
     6→import { useRef, useEffect, useState } from 'react';
     7→import { Stage, Layer, Rect, Line, Circle, Text as KonvaText, Arrow, Transformer, Path } from 'react-konva';
     8→import type Konva from 'konva';
     9→import { useDiagramsStore } from '../../stores/useDiagramsStore';
    10→import { useDiagramEditorStore } from '../../stores/useDiagramEditorStore';
    11→import { getShapeDefinition } from '../../data/shapes/shapesLibrary';
    12→import type { DiagramElement } from '../../types/diagrams';
    13→
    14→interface CanvasProps {
    15→  diagramId: string;
    16→  width: number;
    17→  height: number;
    18→}
    19→
    20→export function Canvas({ diagramId, width, height }: CanvasProps) {
    21→  const stageRef = useRef<Konva.Stage>(null);
    22→  const transformerRef = useRef<Konva.Transformer>(null);
    23→
    24→  const diagram = useDiagramsStore((s) => s.getDiagram(diagramId));
    25→  const updateDiagram = useDiagramsStore((s) => s.updateDiagram);
    26→
    27→  const currentTool = useDiagramEditorStore((s) => s.currentTool);
    28→  const selectedElementIds = useDiagramEditorStore((s) => s.selectedElementIds);
    29→  const selectElement = useDiagramEditorStore((s) => s.selectElement);
    30→  const clearSelection = useDiagramEditorStore((s) => s.clearSelection);
    31→
    32→  const [elements, setElements] = useState<DiagramElement[]>(diagram?.elements || []);
    33→
    34→  // Sync elements from diagram store
    35→  useEffect(() => {
    36→    if (diagram) {
    37→      setElements(diagram.elements);
    38→    }
    39→  }, [diagram]);
    40→
    41→  // Update transformer when selection changes
    42→  useEffect(() => {
    43→    if (!transformerRef.current || !stageRef.current) return;
    44→
    45→    const selectedNodes = selectedElementIds
    46→      .map((id) => stageRef.current?.findOne(`#${id}`))
    47→      .filter((node): node is Konva.Node => node !== undefined);
    48→
    49→    transformerRef.current.nodes(selectedNodes);
    50→    transformerRef.current.getLayer()?.batchDraw();
    51→  }, [selectedElementIds]);
    52→
    53→  if (!diagram) return null;
    54→
    55→  const handleStageClick = (e: Konva.KonvaEventObject<MouseEvent>) => {
    56→    // Click on empty area - deselect
    57→    if (e.target === e.target.getStage()) {
    58→      clearSelection();
    59→      return;
    60→    }
    61→  };
    62→
    63→  const handleElementClick = (id: string, e: Konva.KonvaEventObject<MouseEvent>) => {
    64→    // P1: Prevent interaction with locked elements
    65→    const element = elements.find((el) => el.id === id);
    66→    if (element?.locked) return;
    67→
    68→    if (currentTool === 'select') {
    69→      e.cancelBubble = true;
    70→      selectElement(id, e.evt.shiftKey);
    71→    }
    72→  };
    73→
    74→  const handleElementDragEnd = (id: string, e: Konva.KonvaEventObject<DragEvent>) => {
    75→    const node = e.target;
    76→    const draggedElement = elements.find((el) => el.id === id);
    77→    if (!draggedElement) return;
    78→
    79→    const deltaX = node.x() - draggedElement.x;
    80→    const deltaY = node.y() - draggedElement.y;
    81→
    82→    // If element is grouped, move all elements in the group
    83→    if (draggedElement.groupId) {
    84→      const updatedElements = elements.map((el) => {
    85→        if (el.groupId === draggedElement.groupId) {
    86→          return { ...el, x: el.x + deltaX, y: el.y + deltaY };
    87→        }
    88→        return el;
    89→      });
    90→
    91→      setElements(updatedElements);
    92→      updateDiagram(diagramId, { elements: updatedElements });
    93→    } else {
    94→      // Move single element
    95→      const updatedElements = elements.map((el) =>
    96→        el.id === id ? { ...el, x: node.x(), y: node.y() } : el
    97→      );
    98→
    99→      setElements(updatedElements);
   100→      updateDiagram(diagramId, { elements: updatedElements });
   101→    }
   102→  };
   103→
   104→  const handleTransformEnd = (id: string, e: Konva.KonvaEventObject<Event>) => {
   105→    const node = e.target;
   106→    const scaleX = node.scaleX();
   107→    const scaleY = node.scaleY();
   108→
   109→    // Reset scale and update width/height
   110→    node.scaleX(1);
   111→    node.scaleY(1);
   112→
   113→    const updatedElements = elements.map((el) =>
   114→      el.id === id
   115→        ? {
   116→            ...el,
   117→            x: node.x(),
   118→            y: node.y(),
   119→            width: Math.max(5, node.width() * scaleX),
   120→            height: Math.max(5, node.height() * scaleY),
   121→            rotation: node.rotation(),
   122→          }
   123→        : el
   124→    );
   125→
   126→    setElements(updatedElements);
   127→    updateDiagram(diagramId, { elements: updatedElements });
   128→  };
   129→
   130→  return (
   131→    <Stage
   132→      ref={stageRef}
   133→      width={width}
   134→      height={height}
   135→      onClick={handleStageClick}
   136→      draggable={currentTool === 'select'}
   137→      className="bg-background-light dark:bg-background-dark"
   138→    >
   139→      {/* Grid Layer */}
   140→      <Layer>
   141→        <GridBackground width={width} height={height} gridSize={diagram.canvasState.gridSize} />
   142→      </Layer>
   143→
   144→      {/* Elements Layer */}
   145→      <Layer>
   146→        {elements
   147→          .filter((element) => !element.hidden) // P1: Filter out hidden elements
   148→          .map((element) => (
   149→            <DiagramElementComponent
   150→              key={element.id}
   151→              element={element}
   152→              onClick={(e) => handleElementClick(element.id, e)}
   153→              onDragEnd={(e) => handleElementDragEnd(element.id, e)}
   154→              onTransformEnd={(e) => handleTransformEnd(element.id, e)}
   155→              draggable={currentTool === 'select' && !element.locked} // P1: Disable dragging locked elements
   156→            />
   157→          ))}
   158→
   159→        {/* Transformer for selected elements */}
   160→        <Transformer ref={transformerRef} />
   161→      </Layer>
   162→    </Stage>
   163→  );
   164→}
   165→
   166→// Grid Background Component
   167→interface GridBackgroundProps {
   168→  width: number;
   169→  height: number;
   170→  gridSize: number;
   171→}
   172→
   173→function GridBackground({ width, height, gridSize }: GridBackgroundProps) {
   174→  const lines: React.ReactElement[] = [];
   175→
   176→  // Vertical lines
   177→  for (let i = 0; i < width / gridSize; i++) {
   178→    lines.push(
   179→      <Line
   180→        key={`v-${i}`}
   181→        points={[i * gridSize, 0, i * gridSize, height]}
   182→        stroke="#e5e5e5"
   183→        strokeWidth={0.5}
   184→        listening={false}
   185→      />
   186→    );
   187→  }
   188→
   189→  // Horizontal lines
   190→  for (let i = 0; i < height / gridSize; i++) {
   191→    lines.push(
   192→      <Line
   193→        key={`h-${i}`}
   194→        points={[0, i * gridSize, width, i * gridSize]}
   195→        stroke="#e5e5e5"
   196→        strokeWidth={0.5}
   197→        listening={false}
   198→      />
   199→    );
   200→  }
   201→
   202→  return <>{lines}</>;
   203→}
   204→
   205→// Diagram Element Component (renders different shapes)
   206→interface DiagramElementComponentProps {
   207→  element: DiagramElement;
   208→  onClick: (e: Konva.KonvaEventObject<MouseEvent>) => void;
   209→  onDragEnd: (e: Konva.KonvaEventObject<DragEvent>) => void;
   210→  onTransformEnd: (e: Konva.KonvaEventObject<Event>) => void;
   211→  draggable: boolean;
   212→}
   213→
   214→function DiagramElementComponent({
   215→  element,
   216→  onClick,
   217→  onDragEnd,
   218→  onTransformEnd,
   219→  draggable,
   220→}: DiagramElementComponentProps) {
   221→  const commonProps = {
   222→    id: element.id,
   223→    x: element.x,
   224→    y: element.y,
   225→    rotation: element.rotation || 0,
   226→    draggable,
   227→    onClick,
   228→    onDragEnd,
   229→    onTransformEnd,
   230→  };
   231→
   232→  const styleProps = {
   233→    fill: element.fill || 'transparent',
   234→    stroke: element.stroke || '#000000',
   235→    strokeWidth: element.strokeWidth || 2,
   236→  };
   237→
   238→  // P0: Handle shape library shapes
   239→  if (element.type === 'shape' && element.shapeId) {
   240→    const shapeDef = getShapeDefinition(element.shapeId);
   241→
   242→    // Path-based shape
   243→    if (element.pathData || shapeDef?.pathData) {
   244→      return (
   245→        <Path
   246→          {...commonProps}
   247→          {...styleProps}
   248→          data={element.pathData || shapeDef?.pathData || ''}
   249→          scaleX={element.width / (shapeDef?.defaultProps.width || element.width)}
   250→          scaleY={element.height / (shapeDef?.defaultProps.height || element.height)}
   251→        />
   252→      );
   253→    }
   254→
   255→    // Primitive-based shape
   256→    if (shapeDef?.primitiveType === 'rectangle') {
   257→      return (
   258→        <Rect
   259→          {...commonProps}
   260→          {...styleProps}
   261→          width={element.width}
   262→          height={element.height}
   263→          cornerRadius={element.cornerRadius || 0}
   264→        />
   265→      );
   266→    }
   267→
   268→    if (shapeDef?.primitiveType === 'circle') {
   269→      return (
   270→        <Circle
   271→          {...commonProps}
   272→          {...styleProps}
   273→          radius={Math.min(element.width, element.height) / 2}
   274→        />
   275→      );
   276→    }
   277→
   278→    if (shapeDef?.primitiveType === 'ellipse') {
   279→      return (
   280→        <Circle
   281→          {...commonProps}
   282→          {...styleProps}
   283→          radiusX={element.width / 2}
   284→          radiusY={element.height / 2}
   285→        />
   286→      );
   287→    }
   288→  }
   289→
   290→  switch (element.type) {
   291→    case 'rectangle':
   292→      return (
   293→        <Rect
   294→          {...commonProps}
   295→          {...styleProps}
   296→          width={element.width}
   297→          height={element.height}
   298→          cornerRadius={element.cornerRadius || 0}
   299→        />
   300→      );
   301→
   302→    case 'circle':
   303→      return (
   304→        <Circle
   305→          {...commonProps}
   306→          {...styleProps}
   307→          radius={Math.min(element.width, element.height) / 2}
   308→        />
   309→      );
   310→
   311→    case 'ellipse':
   312→      return (
   313→        <Circle
   314→          {...commonProps}
   315→          {...styleProps}
   316→          radiusX={element.width / 2}
   317→          radiusY={element.height / 2}
   318→        />
   319→      );
   320→
   321→    case 'text':
   322→      return (
   323→        <KonvaText
   324→          {...commonProps}
   325→          text={element.text || 'Text'}
   326→          fontSize={element.fontSize || 16}
   327→          fontFamily={element.fontFamily || 'Arial'}
   328→          fontStyle={element.fontWeight === 'bold' ? 'bold' : 'normal'}
   329→          fill={element.fill || '#000000'}
   330→          align={element.textAlign || 'left'}
   331→          width={element.width}
   332→        />
   333→      );
   334→
   335→    case 'line':
   336→      return (
   337→        <Line
   338→          {...commonProps}
   339→          {...styleProps}
   340→          points={[
   341→            0,
   342→            0,
   343→            element.endPoint ? element.endPoint.x - element.x : element.width,
   344→            element.endPoint ? element.endPoint.y - element.y : element.height,
   345→          ]}
   346→        />
   347→      );
   348→
   349→    case 'arrow':
   350→      return (
   351→        <Arrow
   352→          {...commonProps}
   353→          {...styleProps}
   354→          points={[
   355→            0,
   356→            0,
   357→            element.endPoint ? element.endPoint.x - element.x : element.width,
   358→            element.endPoint ? element.endPoint.y - element.y : element.height,
   359→          ]}
   360→          pointerLength={10}
   361→          pointerWidth={10}
   362→        />
   363→      );
   364→
   365→    default:
   366→      return null;
   367→  }
   368→}
   369→

