   304→        canvasState: { ...canvasState },
   305→      });
   306→
   307→      // Limit history size
   308→      if (newHistory.length > state.maxHistorySize) {
   309→        newHistory.shift();
   310→        return {
   311→          history: newHistory,
   312→          currentHistoryIndex: newHistory.length - 1,
   313→        };
   314→      }
   315→
   316→      return {
   317→        history: newHistory,
   318→        currentHistoryIndex: newHistory.length - 1,
   319→      };
   320→    });
   321→  },
   322→
