   324→    const { history, currentHistoryIndex } = get();
   325→    if (currentHistoryIndex <= 0) return undefined;
   326→
   327→    const newIndex = currentHistoryIndex - 1;
   328→    set({ currentHistoryIndex: newIndex });
   329→    return history[newIndex];
   330→  },
   331→
   332→  redo: () => {
   333→    const { history, currentHistoryIndex } = get();
   334→    if (currentHistoryIndex >= history.length - 1) return undefined;
   335→
   336→    const newIndex = currentHistoryIndex + 1;
   337→    set({ currentHistoryIndex: newIndex });
   338→    return history[newIndex];
   339→  },
   340→
   341→  canUndo: () => {
   342→    const { currentHistoryIndex } = get();
   343→    return currentHistoryIndex > 0;
   344→  },
   345→
   346→  canRedo: () => {
   347→    const { history, currentHistoryIndex } = get();
   348→    return currentHistoryIndex < history.length - 1;
   349→  },
   350→}));
