    defaultProps: {
      type: 'shape',
      width: 120,
      height: 80,
      fill: 'var(--accent-purple)',
      stroke: 'var(--accent-purple)',
      strokeWidth: 2,
      zIndex: 1,
    },
  },

  // Data / Input/Output
  {
    id: 'flowchart-data',
    name: 'Data',
    category: 'flowchart',
    keywords: ['data', 'input', 'output', 'parallelogram', 'io'],
    thumbnail: 'parallelogram',
    pathData: 'M 20 0 L 120 0 L 100 60 L 0 60 Z',
    defaultProps: {
      type: 'shape',
      width: 120,
      height: 60,
      fill: 'var(--accent-magenta)',
