    },
  },

  // Preparation
  {
    id: 'flowchart-preparation',
    name: 'Preparation',
    category: 'flowchart',
    keywords: ['preparation', 'setup', 'hexagon'],
    thumbnail: 'hexagon',
    pathData: 'M 30 0 L 90 0 L 120 30 L 90 60 L 30 60 L 0 30 Z',
    defaultProps: {
      type: 'shape',
      width: 120,
      height: 60,
      fill: 'hsl(330, 70%, 55%)', // Magenta
