      strokeWidth: 2,
      zIndex: 1,
    },
  },

  // Circle
  {
    id: 'basic-circle',
    name: 'Circle',
    category: 'basic',
    keywords: ['circle', 'round', 'dot'],
    thumbnail: 'circle',
    primitiveType: 'circle',
    defaultProps: {
      type: 'shape',
      width: 80,
      height: 80,
      fill: 'transparent',
      stroke: 'var(--text-light-primary)',
      strokeWidth: 2,
      zIndex: 1,
    },
  },

  // Triangle
  {
    id: 'basic-triangle',
    name: 'Triangle',
    category: 'basic',
    keywords: ['triangle', 'arrow', 'point'],
    thumbnail: 'triangle',
    pathData: 'M 40 0 L 80 80 L 0 80 Z',
    defaultProps: {
      type: 'shape',
      width: 80,
      height: 80,
      fill: 'transparent',
      stroke: 'var(--text-light-primary)',
      strokeWidth: 2,
      zIndex: 1,
    },
  },

  // Diamond
  {
    id: 'basic-diamond',
    name: 'Diamond',
    category: 'basic',
    keywords: ['diamond', 'rhombus'],
    thumbnail: 'diamond',
    pathData: 'M 40 0 L 80 40 L 40 80 L 0 40 Z',
    defaultProps: {
      type: 'shape',
      width: 80,
      height: 80,
      fill: 'transparent',
      stroke: 'var(--text-light-primary)',
      strokeWidth: 2,
      zIndex: 1,
    },
  },

  // Pentagon
  {
    id: 'basic-pentagon',
    name: 'Pentagon',
    category: 'basic',
    keywords: ['pentagon', '5-sided'],
    thumbnail: 'pentagon',
    pathData: 'M 40 0 L 80 30 L 64 80 L 16 80 L 0 30 Z',
    defaultProps: {
      type: 'shape',
      width: 80,
      height: 80,
