     6→import { useState } from 'react';
     7→import { ChevronLeft, ChevronRight, Search } from 'lucide-react';
     8→import { shapeLibrary, searchShapes } from '../../data/shapes/shapesLibrary';
     9→import type { ShapeDefinition, ShapeCategory } from '../../types/shapes';
    10→
    11→interface ShapePaletteProps {
    12→  onShapeDragStart: (shape: ShapeDefinition, startX: number, startY: number) => void;
    13→  isOpen?: boolean;
    14→  onToggle?: () => void;
    15→}
    16→
    17→export function ShapePalette({ onShapeDragStart, isOpen = true, onToggle }: ShapePaletteProps) {
    18→  const [selectedCategory, setSelectedCategory] = useState<ShapeCategory>('flowchart');
    19→  const [searchQuery, setSearchQuery] = useState('');
    20→
    21→  const categories: Array<{ id: ShapeCategory; label: string }> = [
    22→    { id: 'flowchart', label: 'Flowchart' },
    23→    { id: 'basic', label: 'Basic' },
    24→    { id: 'uml', label: 'UML' },
    25→    { id: 'network', label: 'Network' },
    26→  ];
    27→
    28→  // Filter shapes by search query or selected category
    29→  const shapes = searchQuery
    30→    ? searchShapes(searchQuery)
    31→    : shapeLibrary[selectedCategory];
    32→
    33→  const handleShapeMouseDown = (shape: ShapeDefinition, e: React.MouseEvent) => {
    34→    e.preventDefault();
    35→    onShapeDragStart(shape, e.clientX, e.clientY);
    36→  };
    37→
    38→  if (!isOpen) {
    39→    return (
    40→      <div className="w-10 bg-surface-light-base dark:bg-surface-dark-base border-r border-border-light dark:border-border-dark flex flex-col items-center py-3">
    41→        <button
    42→          onClick={onToggle}
    43→          className="p-2 rounded-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
    44→          aria-label="Open shape palette"
    45→        >
    46→          <ChevronRight className="w-5 h-5 text-text-light-secondary dark:text-text-dark-secondary" />
    47→        </button>
    48→      </div>
    49→    );
    50→  }
    51→
    52→  return (
    53→    <div className="w-60 bg-surface-light-base dark:bg-surface-dark-base border-r border-border-light dark:border-border-dark flex flex-col">
    54→      {/* Header */}
    55→      <div className="flex items-center justify-between p-3 border-b border-border-light dark:border-border-dark">
    56→        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
    57→          Shapes
    58→        </h3>
    59→        <button
    60→          onClick={onToggle}
    61→          className="p-1 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
    62→          aria-label="Close shape palette"
    63→        >
    64→          <ChevronLeft className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
    65→        </button>
    66→      </div>
    67→
    68→      {/* Search */}
    69→      <div className="p-3 border-b border-border-light dark:border-border-dark">
    70→        <div className="relative">
    71→          <Search className="absolute left-2 top-1/2 transform -translate-y-1/2 w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
    72→          <input
    73→            type="text"
    74→            placeholder="Search shapes..."
    75→            value={searchQuery}
    76→            onChange={(e) => setSearchQuery(e.target.value)}
    77→            className="w-full pl-8 pr-3 py-1.5 text-sm rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
    78→          />
    79→        </div>
    80→      </div>
    81→
    82→      {/* Categories */}
    83→      {!searchQuery && (
    84→        <div className="flex flex-col gap-1 p-2 border-b border-border-light dark:border-border-dark">
    85→          {categories.map((category) => {
    86→            const count = shapeLibrary[category.id].length;
    87→            const isDisabled = count === 0;
    88→            const isSelected = selectedCategory === category.id;
    89→
    90→            return (
    91→              <button
    92→                key={category.id}
    93→                onClick={() => !isDisabled && setSelectedCategory(category.id)}
    94→                disabled={isDisabled}
    95→                className={`
    96→                  flex items-center justify-between px-3 py-2 text-sm rounded-lg transition-colors
    97→                  ${isSelected
    98→                    ? 'bg-accent-magenta/10 dark:bg-accent-magenta/20 text-accent-magenta'
    99→                    : isDisabled
   100→                    ? 'text-text-light-tertiary dark:text-text-dark-tertiary cursor-not-allowed opacity-50'
   101→                    : 'text-text-light-primary dark:text-text-dark-primary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   102→                  }
   103→                `}
   104→              >
   105→                <span>{category.label}</span>
   106→                <span className="text-xs opacity-60">{count}</span>
   107→              </button>
   108→            );
   109→          })}
   110→        </div>
   111→      )}
   112→
   113→      {/* Shape Grid */}
   114→      <div className="flex-1 overflow-y-auto p-3">
   115→        {shapes.length === 0 ? (
   116→          <div className="text-center py-8 text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
